import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api, { formatCurrency } from '../../utils/api';
import { useToast } from '../../context/ToastContext';

export default function CartPage() {
  const [cart, setCart] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showCheckout, setShowCheckout] = useState(false);
  const [checkoutForm, setCheckoutForm] = useState({ shippingAddress: '', shippingPhone: '', paymentMethod: 'bank_transfer', notes: '' });
  const [placing, setPlacing] = useState(false);
  const { addToast } = useToast();
  const navigate = useNavigate();

  useEffect(() => { loadCart(); }, []);

  const loadCart = async () => {
    try {
      const res = await api.get('/cart');
      setCart(res.data.cart);
    } catch { addToast('Không thể tải giỏ hàng', 'error'); }
    finally { setLoading(false); }
  };

  const updateQty = async (itemID, qty) => {
    await api.put(`/cart/items/${itemID}`, { quantity: qty });
    loadCart();
  };

  const removeItem = async (itemID) => {
    await api.delete(`/cart/items/${itemID}`);
    addToast('Đã xóa sản phẩm', 'info');
    loadCart();
  };

  const placeOrder = async () => {
    if (!checkoutForm.shippingAddress || !checkoutForm.shippingPhone) {
      return addToast('Vui lòng nhập địa chỉ và SĐT giao hàng', 'error');
    }
    setPlacing(true);
    try {
      const res = await api.post('/orders', checkoutForm);
      addToast('Đặt hàng thành công! 🎉', 'success');
      navigate(`/my-orders`);
    } catch (err) {
      addToast(err.response?.data?.message || 'Lỗi đặt hàng', 'error');
    } finally { setPlacing(false); }
  };

  if (loading) return <div className="loading"><div className="spinner" /><span>Đang tải giỏ hàng...</span></div>;

  const items = cart?.items || [];

  return (
    <div className="page">
      <div className="page-header">
        <h1>🛒 Giỏ hàng</h1>
        <p>{items.length} sản phẩm</p>
      </div>

      {items.length === 0 ? (
        <div className="empty-state">
          <div className="icon">🛒</div>
          <p>Giỏ hàng trống</p>
          <button className="btn btn-primary" style={{ marginTop: 16 }} onClick={() => navigate('/shop')}>Mua sắm ngay</button>
        </div>
      ) : (
        <div className="grid-2" style={{ alignItems: 'start' }}>
          <div>
            <div className="card">
              {items.map(item => (
                <div key={item.cartItemID} style={{ display: 'flex', gap: 12, padding: '14px 0', borderBottom: '1px solid var(--border)' }}>
                  <img src={item.imageUrl || 'https://via.placeholder.com/80'} alt="" style={{ width: 72, height: 72, objectFit: 'cover', borderRadius: 8 }} onError={e => e.target.src='https://via.placeholder.com/80'} />
                  <div style={{ flex: 1 }}>
                    <div style={{ fontWeight: 600, fontSize: 14 }}>{item.productName}</div>
                    <div style={{ color: 'var(--accent)', fontWeight: 700, marginTop: 2 }}>{formatCurrency(item.price)}</div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginTop: 8 }}>
                      <button className="btn btn-secondary btn-sm" onClick={() => updateQty(item.cartItemID, item.quantity - 1)}>−</button>
                      <span style={{ fontSize: 14, fontWeight: 600, minWidth: 24, textAlign: 'center' }}>{item.quantity}</span>
                      <button className="btn btn-secondary btn-sm" onClick={() => updateQty(item.cartItemID, item.quantity + 1)}>+</button>
                      <button className="btn btn-danger btn-sm" onClick={() => removeItem(item.cartItemID)}>🗑</button>
                    </div>
                  </div>
                  <div style={{ fontFamily: 'Syne', fontWeight: 700, fontSize: 15, color: 'var(--text)' }}>
                    {formatCurrency(item.price * item.quantity)}
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div>
            <div className="card">
              <div className="card-title">Tổng đơn hàng</div>
              {items.map(item => (
                <div key={item.cartItemID} style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, marginBottom: 6 }}>
                  <span style={{ color: 'var(--text-muted)' }}>{item.productName} × {item.quantity}</span>
                  <span>{formatCurrency(item.price * item.quantity)}</span>
                </div>
              ))}
              <div style={{ borderTop: '1px solid var(--border)', marginTop: 12, paddingTop: 12, display: 'flex', justifyContent: 'space-between' }}>
                <span style={{ fontWeight: 700 }}>Tổng cộng</span>
                <span style={{ fontFamily: 'Syne', fontSize: 20, fontWeight: 800, color: 'var(--accent)' }}>{formatCurrency(cart?.total || 0)}</span>
              </div>
              <button className="btn btn-primary" style={{ width: '100%', justifyContent: 'center', marginTop: 16 }} onClick={() => setShowCheckout(true)}>
                Đặt hàng ngay →
              </button>
            </div>
          </div>
        </div>
      )}

      {showCheckout && (
        <div className="modal-overlay" onClick={() => setShowCheckout(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <div className="modal-title">📋 Xác nhận đặt hàng</div>
              <button className="modal-close" onClick={() => setShowCheckout(false)}>×</button>
            </div>
            <div className="form-group">
              <label className="form-label">Địa chỉ giao hàng *</label>
              <input className="form-control" value={checkoutForm.shippingAddress} onChange={e => setCheckoutForm(p => ({ ...p, shippingAddress: e.target.value }))} placeholder="Số nhà, đường, quận, thành phố..." />
            </div>
            <div className="form-group">
              <label className="form-label">Số điện thoại *</label>
              <input className="form-control" value={checkoutForm.shippingPhone} onChange={e => setCheckoutForm(p => ({ ...p, shippingPhone: e.target.value }))} placeholder="0912..." />
            </div>
            <div className="form-group">
              <label className="form-label">Phương thức thanh toán</label>
              <select className="form-control" value={checkoutForm.paymentMethod} onChange={e => setCheckoutForm(p => ({ ...p, paymentMethod: e.target.value }))}>
                <option value="bank_transfer">Chuyển khoản ngân hàng</option>
                <option value="credit_card">Thẻ tín dụng</option>
                <option value="e_wallet">Ví điện tử</option>
                <option value="cod">Thanh toán khi nhận hàng</option>
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">Ghi chú</label>
              <input className="form-control" value={checkoutForm.notes} onChange={e => setCheckoutForm(p => ({ ...p, notes: e.target.value }))} placeholder="Yêu cầu đặc biệt..." />
            </div>
            <div style={{ background: 'var(--bg-card2)', padding: 12, borderRadius: 8, marginBottom: 16 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                <span>Tổng thanh toán:</span>
                <span style={{ fontFamily: 'Syne', fontWeight: 800, color: 'var(--accent)' }}>{formatCurrency(cart?.total || 0)}</span>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setShowCheckout(false)}>Hủy</button>
              <button className="btn btn-primary" onClick={placeOrder} disabled={placing}>
                {placing ? '⏳ Đang đặt hàng...' : '✅ Xác nhận đặt hàng'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
